 7→export default function Accordion({
 8→  items,
 9→  mt,
10→  mb,
11→  ml,
12→  mr,
13→  testID,
14→  iconSeeLess,
15→  iconSeeMore,
16→  iconColor,
17→  title,
18→  type,
19→  isMap,
20→  version = '1.0',
21→  bgColor,
22→  isStroke = true,
23→  scrollEnabled,
24→}: PropsAccordion) {
25→  const [itemsCard, setItemsCard] = useState<Array<propsItems>>([]);
26→
27→  const onPressCard = (id: number) => {
28→    setItemsCard(
29→      itemsCard.map((item: propsItems) => {
30→        return item.id === id
31→          ? { ...item, visible: !item.visible }
32→          : { ...item, visible: false };
33→      }),
34→    );
35→  };
36→
37→  const traverseArray = useCallback(() => {
38→    const array: propsItems[] = [];
39→    items.forEach((value, index) => {
40→      array.push({
41→        ...value,
42→        id: index,
43→        visible: value?.visible || false,
44→      });
45→    });
46→
47→    setItemsCard(array);
48→  }, [items]);
49→
50→  useEffect(() => {
51→    traverseArray();
52→  }, [traverseArray]);
53→
54→  return version === '1.0' ? (
55→    <ViewV1
56→      mt={mt}
57→      ml={ml}
58→      mb={mb}
59→      mr={mr}
60→      testID={testID}
61→      items={itemsCard}
