63→      iconSeeLess={iconSeeLess}
64→      iconSeeMore={iconSeeMore}
65→      iconColor={iconColor}
66→      title={title}
67→      type={type}
68→      isMap={isMap}
69→    />
70→  ) : (
71→    <ViewV2
72→      mt={mt}
73→      ml={ml}
74→      mb={mb}
75→      mr={mr}
76→      testID={testID}
77→      items={itemsCard}
